#[allow(unused_macros)]
macro_rules! trace {
    ($var:expr) => {
        let _ = writeln!(&mut std::io::stderr(), ">>> {} = {:?}", stringify!($var), $var);
    };
    ($($args:expr),*) => { trace!(($($args),*)) }
}

#[allow(unused_macros)]
macro_rules! put {
    ($var:expr) => {
        let _ = writeln!(&mut std::io::stdout(), "{}", $var);
    };
    ($var:expr, $($args:expr),*) => {
        let _ = write!(&mut std::io::stdout(), "{} ", $var);
        put!($($args),*);
    };
}

fn gcd(a: u64, b: u64) -> u64 { if b == 0 { a } else { gcd(b, a % b) } }
fn main() {
    let mut sc = Scanner::new();
    let l: u64 = sc.cin();
    let r: u64 = sc.cin();
    let x: u64 = sc.cin();
    let y: u64 = sc.cin();

    let mut divs = vec![];
    for i in 1..y {
        if i * i > y {
            break
        } else if i * i == y {
            divs.push(i);
        } else if y % i == 0 {
            divs.push(i);
            divs.push(y/i);
        }
    }
    // trace!(divs);

    let mut ans = 0;
    for k in divs.iter() {
        let a = k * x;
        let b = y / k;
        if l <= a && a <= r && l <= b && b <= r && gcd(a, b) == x {
            ans += 1;
        }
    }
    put!(ans);
}

